import re


@app.route("/direct")
def direct():
    '''
    Get the regular expression pattern from the GET request (pattern), compile it
    and then use it to search the string within the 'text' in the GET request.
    '''
    pattern = request.args.get('pattern', '')
    text = request.args.get('text', '')

    # Validate pattern length to prevent ReDoS
    if len(pattern) > 100:
        return "Pattern too long", 400

    # Disallow dangerous regex constructs that can lead to ReDoS
    # Common problematic patterns: nested quantifiers, excessive backtracking triggers
    # Simple heuristic: reject patterns with repeated quantifiers like **, ++, *+, +*, etc.
    dangerous_patterns = [
        r'\*\*', r'\+\+', r'\*\+', r'\+\*', r'\?\*', r'\*\?', r'\?\+', r'\+\?',
        r'\{[^}]*\}[^?*+]*[?*+]',  # rough heuristic for quantifier after quantifier
    ]
    for dp in dangerous_patterns:
        if re.search(dp, pattern):
            return "Invalid pattern: potentially dangerous regex", 400

    try:
        compiled = re.compile(pattern)
    except re.error:
        return "Invalid regex pattern", 400

    if compiled.search(text):
        return "Match found"
    else:
        return "No match"
